import json, re, urllib.request

all_products = []
for page in range\(1, 10\):
    url = f'https://www.footlv.store/products.json?limit=250&page={page}'
    req = urllib.request.Request\(url, headers={'User-Agent': 'Mozilla/5.0'}\)
    data = json.loads\(urllib.request.urlopen\(req, timeout=15\).read\(\)\)
    prods = data['products']
    if not prods:
        break
    all_products.extend\(prods\)

img_url_to_product = {}
for p in all_products:
    names = None
    for opt in p.get\('options', []\):
        if opt['name'].lower\(\) in \('name', 'player', 'player name', 'names'\):
            names = opt['values']
            break
    for img in p.get\('images', []\):
        src = img.get\('src', ''\).split\('?'\)[0]
        img_url_to_product[src] = \(p['handle'], p['title'], names\)

content = open\('/Users/nocap/Downloads/Virenza - O/src/external-products.ts', encoding='utf-8'\).read\(\)

lines = content.split\('\\n'\)
current_id = None
current_name = None
current_imgs = []
our_cdn_imgs = {}

for line in lines:
    id_match = re.search\(r"id: '\(jg-[^']+\)'", line\)
    if id_match:
        if current_id and current_imgs:
            our_cdn_imgs[current_id] = \(current_name, current_imgs\)
        current_id = id_match.group\(1\)
        current_name = None
        current_imgs = []
    name_match = re.search\(r"name: '\([^']+\)'", line\)
    if name_match and current_id and current_name is None:
        current_name = name_match.group\(1\)
    cdn_match = re.findall\(r"\(https://cdn\\.shopify[^'\\"]+\)", line\)
    if cdn_match and current_id:
        current_imgs.extend\([u.split\('?'\)[0] for u in cdn_match]\)

matched_with_names = {}
matched_no_names = {}

for our_id, \(our_name, urls\) in our_cdn_imgs.items\(\):
    for url in urls:
        if url in img_url_to_product:
            handle, title, names = img_url_to_product[url]
            if names:
                matched_with_names[our_id] = names
            else:
                matched_no_names[our_id] = \(our_name, title\)
            break

print\(f"CDN products with name options: {len\(matched_with_names\)}"\)
print\(f"CDN products without name options on footlv: {len\(matched_no_names\)}"\)
print\(f"\\nNo-name examples:"\)
for oid, \(oname, ftitle\) in list\(matched_no_names.items\(\)\)[:10]:
    print\(f"  {oname} -> footlv: {ftitle}"\)

unmatched_ids = [oid for oid in our_cdn_imgs if oid not in matched_with_names and oid not in matched_no_names]
print\(f"\\nCDN products not found on footlv at all: {len\(unmatched_ids\)}"\)
for oid in unmatched_ids[:5]:
    print\(f"  {oid} | {our_cdn_imgs[oid][0]}"\)
EOF)

